        WordWrap.Builder b = WordWrap.from(r, false); // do not close reader
        IORuntimeException ex = assertThrows(IORuntimeException.class, () -> b.wrap(bad));
        assertNotNull(ex.getCause());
        assertEquals("fail", ex.getCause().getMessage());
